public class MemoryDemo {

    static int counter = 0;  // Method Area (static fields)

    public static void main(String[] args) {
        int localVar = 42;           // Stack frame of main()
        String msg = "hello";        // 'msg' ref on Stack, String obj on Heap
        MemoryDemo obj = new MemoryDemo(); // ref on Stack, object on Heap

        System.out.println(greet(msg));
    }

    static String greet(String name) {  // new Stack frame pushed
        String result = "Hi " + name;   // new String obj on Heap
        return result;                   // frame popped, ref returned
    }
