// Memory layout during greet() execution:
// STACK (LIFO frames):
//   Frame 2 [greet]: name=ref→"hello", result=ref→"Hi hello"
//   Frame 1 [main] : localVar=42, msg=ref→"hello", obj=ref→MemoryDemo@x
// HEAP:
//   "hello" String object
//   "Hi hello" String object  
//   MemoryDemo instance
// METHOD AREA:
//   MemoryDemo.class metadata, counter=0

public class JitDemo {
    // Demonstrates JIT: method gets faster after being called ~10,000 times

    static long compute(int n) {
        long sum = 0;
        for (int i = 0; i < n; i++) sum += i;
        return sum;
    }

    public static void main(String[] args) throws Exception {
        // Phase 1: Interpreted (cold) — first few calls
        for (int i = 0; i < 100; i++) {
            long t = System.nanoTime();
            compute(100_000);
            if (i < 3) System.out.printf("Call %d: %dns (interpreted)%n", i, System.nanoTime()-t);
        }

        // Phase 2: JIT kicks in after ~10,000 invocations (C1 compiler)
        // Phase 3: After ~100,000 invocations (C2 compiler — fully optimized)
        for (int i = 0; i < 200; i++) {
            long t = System.nanoTime();
            compute(100_000);
            if (i > 190) System.out.printf("Call %d: %dns (JIT compiled)%n", i+100, System.nanoTime()-t);
        }
        // Typical output: early calls ~50,000ns, late calls ~500ns (100x faster)
    }
}

public class GcDemo {

    public static void main(String[] args) throws Exception {
        // GC ROOT 1: local variable in main frame
        String alive = "I'm reachable from stack — won't be GC'd";

        // GC ROOT 2: static field (lives as long as class is loaded)
        // GcDemo.CACHED holds a reference — object stays alive

        createGarbage();  // objects inside become unreachable after return

        System.gc();  // hint GC to run (not guaranteed)
        System.runFinalization();
        System.out.println("GC suggested. 'alive' is still: " + alive);
    }

    static void createGarbage() {
        // These objects become unreachable when method returns
        // (no reference escapes to outer scope)
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 1000; i++) {
            sb.append("chunk" + i + " ");  // intermediate Strings also garbage
        }
        String big = sb.toString();   // big string — also garbage after return
        // big and sb go out of scope: eligible for GC
    }

    // Objects referenced from static field = GC roots = always alive
    static final String CACHED = "static reference keeps this alive";
}

