import java.util.*;

public class Q1 {
    static int staticVal = 100;

    public static Map<String, String> describeStorage() {
        Map<String, String> result = new LinkedHashMap<>();
        // staticVal: static field -> stored in Method Area (Metaspace), not stack/heap per se
        // But for this exercise, static fields are NOT on heap and NOT on stack
        result.put("staticVal", "method-area");
        // Local primitives -> stack
        result.put("a", "stack");          // int a = 5
        result.put("b", "stack");          // double b = 3.14
        // References are on stack, but objects they point to are on heap
        result.put("s_ref", "stack");      // reference variable 's'
        result.put("s_obj", "heap");       // actual String object (String Pool on heap)
        result.put("arr_ref", "stack");    // reference variable 'arr'
        result.put("arr_obj", "heap");     // actual int[] array object
        return result;
    }

    public static void main(String[] args) {
        System.out.println(describeStorage());
    }
