import java.util.*;

public class Q2 {
    public static String classLoaderChain(Class<?> clazz) {
        List<String> chain = new ArrayList<>();
        ClassLoader cl = clazz.getClassLoader();
        while (cl != null) {
            chain.add(cl.getClass().getSimpleName());
            cl = cl.getParent();
        }
        chain.add("Bootstrap(null)");
        return String.join(" -> ", chain);
    }

    public static void main(String[] args) {
        System.out.println(classLoaderChain(String.class)); // Bootstrap(null)
        System.out.println(classLoaderChain(Q2.class));     // AppClassLoader -> ... -> Bootstrap(null)
    }
}

