public class Q3 {
    static String KEEP = "static";

    public static int gcEligibleCount() {
        // Objects created in process():
        // 1. new String("alpha") — referenced by 'a' then by 'c'. After return, c gone -> eligible
        // 2. new String("beta")  — referenced by 'b', added to list. After return, list gone -> eligible
        // 3. new String("delta") — referenced by 'd'. After return, d gone -> eligible
        // 4. new ArrayList<>()   — referenced by 'list'. After return, list gone -> eligible
        // Note: a = null before return, but 'alpha' still reachable via 'c' until return
        // KEEP is static -> not eligible
        // String literals "alpha", "beta", "delta" in String Pool may survive
        // But new String(...) creates HEAP objects separate from the pool
        return 4; // alpha-obj, beta-obj, delta-obj, ArrayList-obj
    }

    static void process() {
        String a = new String("alpha");
        String b = new String("beta");
        String c = a;
        a = null;
        String d = new String("delta");
        java.util.List<String> list = new java.util.ArrayList<>();
        list.add(b);
    }

    public static void main(String[] args) {
        process();
        System.out.println(gcEligibleCount()); // 4
    }
}

