    public static boolean[] compareStrings() {
        String a = "abc";
        String b = "abc";             // from String Pool
        String c = new String("abc"); // new heap object
        String d = new String("abc"); // another new heap object

        // Return: [a==b, c==d, c.equals(d)]
        return new boolean[]{false, false, false}; // TODO: fix
    }

    public static void main(String[] args) {
        boolean[] results = compareStrings();
        System.out.println("a==b (literals): "  + results[0]);
        System.out.println("c==d (new Strings): " + results[1]);
        System.out.println("c.equals(d): "       + results[2]);
