problems.solutionCode:
public class Q5 {
    public static boolean[] compareStrings() {
        String a = "abc";
        String b = "abc";             // same String Pool entry -> same reference
        String c = new String("abc"); // new heap object, different reference
        String d = new String("abc"); // another new heap object, different reference

        boolean literalEq  = (a == b);         // true  — both point to String Pool "abc"
        boolean newStrEq   = (c == d);         // false — different heap objects
        boolean valueEq    = c.equals(d);      // true  — same content
        return new boolean[]{literalEq, newStrEq, valueEq};
    }

    public static void main(String[] args) {
        boolean[] results = compareStrings();
        System.out.println("a==b (literals): "    + results[0]); // true
        System.out.println("c==d (new Strings): " + results[1]); // false
        System.out.println("c.equals(d): "        + results[2]); // true
    }
}

