problems.solutionCode:
public class Q6 {
    static int maxDepth = 0;

    public static int maxRecursionDepth() {
        maxDepth = 0;
        try {
            recurse(0);
        } catch (StackOverflowError e) {
            // maxDepth holds the last successful depth
        }
        return maxDepth;
    }

    static void recurse(int depth) {
        maxDepth = depth;       // record current depth
        recurse(depth + 1);     // go deeper — eventually causes StackOverflowError
