problems.solutionCode:
import java.util.*;

public class Q9 {
    public static long measureHeapUsage() {
        Runtime rt = Runtime.getRuntime();
        System.gc();
        long before = rt.totalMemory() - rt.freeMemory();
        System.out.println("Heap before: " + before + " bytes");

        // Allocate 10,000 Strings — keep reference so GC doesn't collect
        List<String> strings = new ArrayList<>(10_000);
        for (int i = 0; i < 10_000; i++) {
            strings.add("string-" + i); // each creates a new String object
        }

        long after = rt.totalMemory() - rt.freeMemory();
        System.out.println("Heap after:  " + after  + " bytes");

        long delta = after - before;
        System.out.println("Delta: " + delta + " bytes (~" + delta/1024 + " KB)");

        // Prevent GC from collecting strings before measurement
        strings.clear();
        return delta;
    }

    public static void main(String[] args) {
        System.out.println("Heap delta: " + measureHeapUsage() + " bytes");
    }
}

