import java.util.concurrent.*;

public class Q12 {
    private static final ThreadLocal<String> requestId = new ThreadLocal<>();

    public static void setRequestId(String id) {
        requestId.set(id);
    }

    public static String getRequestId() {
        return requestId.get();
    }

    public static void main(String[] args) throws InterruptedException {
        CountDownLatch latch = new CountDownLatch(2);

        Thread t1 = new Thread(() -> {
            setRequestId("req-001");
            try { Thread.sleep(50); } catch (InterruptedException e) {}
            System.out.println("Thread-1 requestId: " + getRequestId()); // req-001
            requestId.remove(); // cleanup to prevent memory leak
            latch.countDown();
        });

        Thread t2 = new Thread(() -> {
            setRequestId("req-002");
            try { Thread.sleep(50); } catch (InterruptedException e) {}
            System.out.println("Thread-2 requestId: " + getRequestId()); // req-002
            requestId.remove();
            latch.countDown();
        });

        t1.start();
        t2.start();
        latch.await();
        System.out.println("Main thread requestId: " + getRequestId()); // null
    }
}

problems.description:
Register a JVM shutdown hook that runs cleanup code when the JVM exits:

