problems.solutionCode:
public class Q15 {
    // Circular static initialization analysis:
    // 1. main() accesses A.val -> triggers A's static initialization
    // 2. A's init: val = B.computeA() -> triggers B's static initialization
    // 3. B's init: val = A.getVal() + 10
    //    -> tries to access A, but A is CURRENTLY BEING INITIALIZED
    //    -> JVM returns A's PARTIAL state (val = 0, the default int value!)
    //    -> B.val = 0 + 10 = 10
    // 4. B init completes, B.computeA() returns 42
    // 5. A.val = 42
    // Final: A.val=42, B.val=10 (not 52 as you might expect!)

    static class A {
        static int val = B.computeA(); // triggers B init during A's init
        static int getVal() { return val; }
    }

    static class B {
        // Reads A.getVal() which returns A.val = 0 (A not fully initialized yet!)
        static int val = A.getVal() + 10;
        static int computeA() { return 42; }
    }

    public static void main(String[] args) {
        System.out.println("A.val = " + A.val); // 42
        System.out.println("B.val = " + B.val); // 10 (NOT 52!)
        System.out.println("Circular init caused B to see A's default value 0");
    }
}

