public class Q16 {
    // Pattern 1: Initialization-On-Demand Holder — correct and efficient
    public static class SafeSingleton {
        private final int value;
        private SafeSingleton() { this.value = 42; }

        // Holder class loaded ONLY when getInstance() is first called
        // JVM class loading is thread-safe — no explicit sync needed
        private static final class Holder {
            static final SafeSingleton INSTANCE = new SafeSingleton();
        }

        public static SafeSingleton getInstance() {
            return Holder.INSTANCE;
        }

        public int getValue() { return value; }
    }

    // Pattern 2: FIXED DCL with volatile
    public static class FixedDCL {
        // volatile ensures: (1) visibility, (2) prevents instruction reordering
        // Without volatile: new FixedDCL() could be reordered to:
        //   1. allocate memory, 2. assign reference, 3. run constructor
        // Another thread sees non-null reference but uninitialized object!
        private static volatile FixedDCL instance;
        private int value;
        private FixedDCL() { this.value = 42; }

        public static FixedDCL getInstance() {
            if (instance == null) {
                synchronized (FixedDCL.class) {
                    if (instance == null) {
                        instance = new FixedDCL(); // volatile prevents reorder
                    }
                }
            }
            return instance;
        }
    }

    public static void main(String[] args) {
        SafeSingleton s1 = SafeSingleton.getInstance();
        SafeSingleton s2 = SafeSingleton.getInstance();
        System.out.println("Same instance: " + (s1 == s2));    // true
        System.out.println("Value: " + s1.getValue());          // 42
        System.out.println("IODH: no synchronization overhead after first load");
    }
}

