import java.util.*;

public class Q17 {
    // LEAKY: static map grows forever (GC root keeps all values alive)
    static Map<String, byte[]> leakyCache = new HashMap<>();

    static void processLeaky(String key) {
        // Each call adds 1KB to the unbounded cache — never evicted
        leakyCache.put(key, new byte[1024]);
    }

    // FIXED: LRU cache capped at maxSize entries
    static final int MAX = 1000;
    static Map<String, byte[]> fixedCache = new LinkedHashMap<>(MAX, 0.75f, true) {
        @Override
        protected boolean removeEldestEntry(Map.Entry<String, byte[]> eldest) {
            return size() > MAX; // evict oldest when over limit
        }
    };

    static void processFixed(String key) {
        fixedCache.put(key, new byte[1024]); // auto-evicts when > MAX
    }

    public static void main(String[] args) {
        Runtime rt = Runtime.getRuntime();
        System.gc();
        long start = rt.totalMemory() - rt.freeMemory();

        // Leaky: 10,000 unique keys = 10,000 x 1KB = ~10MB retained
        for (int i = 0; i < 10_000; i++) processLeaky("key-" + i);
        long afterLeak = rt.totalMemory() - rt.freeMemory();

        // Fixed: only MAX=1000 entries retained regardless of inserts
        for (int i = 0; i < 10_000; i++) processFixed("key-" + i);

        System.out.printf("Leaky cache size:  %d entries, heap delta: +%dKB%n",
            leakyCache.size(), (afterLeak - start) / 1024);
        System.out.printf("Fixed cache size:  %d entries (capped at %d)%n",
            fixedCache.size(), MAX);
    }
}

