public class Q19 {
    static volatile long blackhole; // prevent dead-code elimination

    static long compute(int n) {
        long sum = 0;
        for (int i = 1; i <= n; i++) sum += (long) i * i;
        return sum;
    }

    public static long[] runBenchmark() {
        final int BATCHES = 10;
        final int PER_BATCH = 10_000;
        long[] batchNsPerCall = new long[BATCHES];

        for (int batch = 0; batch < BATCHES; batch++) {
            long start = System.nanoTime();
            for (int i = 0; i < PER_BATCH; i++) {
                blackhole = compute(1000); // sink result to prevent JIT elimination
            }
            long elapsed = System.nanoTime() - start;
            batchNsPerCall[batch] = elapsed / PER_BATCH;
        }
        return batchNsPerCall;
    }

    public static void main(String[] args) {
        long[] times = runBenchmark();
        System.out.println("=== JIT Warm-up Benchmark ===");
        for (int i = 0; i < times.length; i++)
            System.out.printf("Batch %2d: %,6d ns/call%s%n",
                i+1, times[i], i < 2 ? " (cold)" : i > 7 ? " (hot/JIT)" : "");

        System.out.printf("%nCold (batch 1): %,d ns  |  Hot (batch 10): %,d ns%n",
            times[0], times[BATCHES-1]);
        System.out.printf("Speedup: %.1fx%n", (double) times[0] / times[BATCHES-1]);
    }
}

