import java.util.*;

public class Q20 {
    static Deque<Integer> stack = new ArrayDeque<>();
    static Map<String, Integer> vars = new HashMap<>();

    static void execute(String[] program) {
        stack.clear();
        vars.clear();
        for (String instr : program) {
            String[] parts = instr.trim().split("\\s+");
            String op = parts[0].toUpperCase();
            switch (op) {
                case "PUSH"  -> stack.push(Integer.parseInt(parts[1]));
                case "POP"   -> stack.pop();
                case "ADD"   -> { int b = stack.pop(); int a = stack.pop(); stack.push(a + b); }
                case "MUL"   -> { int b = stack.pop(); int a = stack.pop(); stack.push(a * b); }
                case "SUB"   -> { int b = stack.pop(); int a = stack.pop(); stack.push(a - b); }
                case "DIV"   -> { int b = stack.pop(); int a = stack.pop(); stack.push(a / b); }
                case "STORE" -> vars.put(parts[1], stack.pop());
                case "LOAD"  -> stack.push(vars.getOrDefault(parts[1], 0));
                case "PRINT" -> System.out.println(stack.pop());
                default      -> throw new IllegalArgumentException("Unknown opcode: " + op);
            }
        }
    }

    public static void main(String[] args) {
        System.out.println("Computing (3 + 4) * 2:");
        execute(new String[]{ "PUSH 3", "PUSH 4", "ADD", "PUSH 2", "MUL", "PRINT" });
        // Output: 14

        System.out.println("\nComputing sum = 10 + 5, then sum * 3:");
        execute(new String[]{
            "PUSH 10", "PUSH 5", "ADD", "STORE sum",
            "LOAD sum", "PUSH 3", "MUL", "PRINT"
        });
        // Output: 45
    }
}
